		this.world.scene.add(group);
	}

	private updateJackpotDisplay() {
		if (!this.jackpotDisplay) return;
		const amount = Math.floor(this.jackpot);
		this.setText('hud', 'jackpot-display', amount > 0 ? `JACKPOT: $${amount.toLocaleString()}` : '');
	}

	private contributeToJackpot(bet: number) {
		// 2% of each bet goes to jackpot
		const contribution = Math.floor(bet * 0.02);
		this.jackpot += contribution;
		this.updateJackpotDisplay();
	}

	private checkJackpotWin(): boolean {
		if (this.jackpot <= 0) return false;
		const hand = this.activeHand;
		if (!hand || hand.cards.length < 2) return false;

		// Suited blackjack (same suit A + 10/J/Q/K) = full jackpot
		if (hand.cards.length === 2 && hand.blackjack) {
			if (hand.cards[0].suit === hand.cards[1].suit) {
				const won = this.jackpot;
				this.bank += won;
				this.audio.playJackpot();
				this.showToast(`JACKPOT WON! $${Math.floor(won).toLocaleString()}!`);
				this.jackpot = 0;
				this.particles.burst(0, TABLE_Y + 0.5, TABLE_Z, 0xffaa00, 40);
				this.saveAllData();
				return true;
			}
		}

		// Three 7s = half jackpot
		if (hand.cards.length >= 3) {
			const sevens = hand.cards.filter(c => c.rank === '7');
			if (sevens.length >= 3) {
				const won = Math.floor(this.jackpot * 0.5);
				this.bank += won;
				this.audio.playJackpot();
				this.showToast(`TRIPLE 7s! $${won.toLocaleString()} JACKPOT!`);
				this.jackpot -= won;
				this.particles.burst(0, TABLE_Y + 0.5, TABLE_Z, 0xff6600, 30);
				this.saveAllData();
				return true;
			}
		}

		return false;
	}

